	MFIFO_DEFINE(_name, sizeof(void *), _count); \
	\
	static const struct { \
		uint16_t size; \
		uint8_t count; \
		uint8_t extra_links; \
	} mem_##_name = { .size = MROUND(_size), .count = _count, \
			  .extra_links = _extra_links }; \
	\
	static struct { \
		void *free; \
		uint8_t pool[MROUND(_size) * (_count)]; \
	} mem_pool_##_name; \
	\
	static struct { \
		void *free; \
		uint8_t pool[sizeof(memq_link_t) * (_count + _extra_links)]; \
